    return {title:title,url:url,style:{layout_flexGroup:1,layout_flexBasisPercent:num}}
}

top=[{"title":"热门人气","url":"https://comic.mkzcdn.com/search/filter/?order=1&page_num={{page}}&page_size=12","style":{"layout_flexBasisPercent":0.4,"layout_flexGrow":1}},
{"title":"更新时间","url":"https://comic.mkzcdn.com/search/filter/?order=2&page_num={{page}}&page_size=12","style":{"layout_flexBasisPercent":0.4,"layout_flexGrow":1}}]



let list = []
list=list.concat(top)

for (let i = 0; i < sort_name.length; i++) {
    list.push(model(sort_name[i],"",1))
    for (let j = 0; j < class_name.length; j++) {
        let t = url.replace("sort",`${sort_url[i]}`).replace("class",`${class_url[j]}`)
        list.push(model(class_name[j],t,0.15))
    }
}
JSON.stringify(list)

