    const result = JSON.parse(response);

    // 校验响应格式，提取categories数据
    if (result.msg === "success" && result.data?.categories && Array.isArray(result.data.categories)) {
        result.data.categories.forEach(category => {
            const categoryUrl = `http://api.daislou.com/novel?sort=1&page={{page}}&categoryId=${category.categoryId}`;
            // 推送分类名称和对应链接
            push(category.categoryName, categoryUrl, 1, 0.2);
        });
    }
});

JSON.stringify(sort);

