const KEY_BASE64 = "ZjA0MWM0OTcxNGQzOTkwOA==";
const IV_BASE64 = "MDEyMzQ1Njc4OWFiY2RlZg==";
var txt = "";
try {
    var keyBytes = java.base64DecodeToByteArray(KEY_BASE64);
    var ivBytes = java.base64DecodeToByteArray(IV_BASE64);
      var crypto = java.createSymmetricCrypto("AES/CBC/PKCS5Padding", keyBytes, ivBytes);
      var decrypted = crypto.decrypt(result);
    txt += java.bytesToStr(decrypted);
    result = txt;
} catch (e) {
    java.log("AES解密失败: " + e.toString());
    result = "解密失败";
}
result
</js>

