@js:
const u = source.key, list = [];
const push = (title, url, flex) => list.push({
  title: title,
  url: url,
  style: {
    layout_flexGrow: 1,
    layout_flexBasisPercent: flex
  }
});
const getDoc = url => org.jsoup.Jsoup.parse(java.ajax(url));
const doc = getDoc(u);
push("・分类・", "", 1);
doc.select('.menu a').forEach(e => push(e.text(), e.attr('href') + "<,index_{{page}}.html>", null));
push("・标签・", "", 1);
doc.select('.panel-default a').forEach(e => push(e.text(), String(e.attr('href')).replace(/\d+\.html$/, '{{page-1}}.html'), null));
push("・书单・", "", 1);
const sUrl = u + "/shudan", sDoc = getDoc(sUrl);
const total = +((sDoc.select('.m-page .disabled').text().match(/\/(\d+)/) || [,0])[1]);
for (let i = 1; i <= total; ++i) {
  let page = i == 1 ? "": `/index_${i}.html`;
  getDoc(sUrl + page).select('.panel-warning .list-group-item a').forEach(e => push(e.text(), e.attr('href'), null));
}
JSON.stringify(list);

