// 定义 Map 函数（使用 source 持久化存储）
function Map(e) {
    const { source } = this;
    let infomap = String(source.getLoginHeader()).replace(/^#/, '');
    infomap = (infomap != "null" && infomap != "" && infomap != null) ? infomap : "{}";
    let map = JSON.parse(infomap);
    return map[e] || "";
}

function setHeaders(mapObj) {
    const { source } = this;
    let old = String(source.getLoginHeader()).replace(/^#/, '');
    let oldMap = (old != "null" && old != "" && old != null) ? JSON.parse(old) : {};
    Object.assign(oldMap, mapObj);
    source.putLoginHeader("#" + JSON.stringify(oldMap));
}

