};

// ==============================================
// 🛠️ 工具函数区
// ==============================================
const all = [];
const flexBasis = { 1: 1, 2: 0.4, 3: 0.25, 4: 0.2, 5: 0.15, 7: 0.1, 10: 0.05 };

function push(title, url, flexBasisPercent, flexGrow, action) {
    const item = {
        title: title,
        url: url,
        style: {
            layout_flexGrow: flexGrow === 0 ? 0 : 1,
            layout_flexBasisPercent: flexBasisPercent
        }
    };
    if (action) Object.assign(item, action);
    all.push(item);
}

function show(key, value) {
    setHeaders.call(this, { [key]: value });
    java.refreshExplore();
}

function getVal(key) {
    return Map.call(this, key) || "";
}

function renderTemplate(template, data) {
    let result = template.replace(/{{#if (\w+)}}(.*?){{\/if}}/g, (match, key, content) => {
        return data[key] ? content : "";
    });
    result = result.replace(/{{(\w+)}}/g, (match, key) => {
        let val = data[key];
        return val !== undefined ? val : "";
    });
    return result;
}

function buildUrl(tag) {
    const orderMap = { "人气": "hits", "最新": "addtime", "评分": "score" };
    let orderLabel = getVal.call(this, "order") || CONFIG.filters[0].default;
    let order = orderMap[orderLabel] || "hits";

    const finishMap = { "全部": "0", "连载": "0", "完结": "1" };
    let finishLabel = getVal.call(this, "finish") || CONFIG.filters[1].default;
    let finish = finishMap[finishLabel] || "0";

    const payMap = { "全部": "0", "免费": "0", "付费": "1" };
    let payLabel = getVal.call(this, "pay") || CONFIG.filters[2].default;
    let pay = payMap[payLabel] || "0";

    const listMap = {};
    CONFIG.filters[3].options.forEach(opt => { listMap[opt.label] = opt.value; });
    let listLabel = getVal.call(this, "list") || CONFIG.filters[3].default;
    let list = listMap[listLabel] || "0";

    const finalTag = (tag && tag !== "") ? tag : "";

    const data = {
        order: order,
        finish: finish,
        pay: pay,
        list: list,
        tag: finalTag,
        page: "{{page}}"
    };
    let url = CONFIG.apiBase + renderTemplate(CONFIG.urlTemplate, data);
    url = url.replace(/&+/g, '&').replace(/[?&]$/, '');
    return url;
}

function generateSelectAction(filter) {
    const map = {};
    filter.options.forEach(o => map[o.label] = o.value);
    return `
        const map = ${JSON.stringify(map)};
        show(map[infoMap['${filter.name}']], '${filter.key}');
    `;
}

// ==============================================
// 🚀 布局生成
// ==============================================
try {
    const self = this;

    push("🔍 筛选条件", "", flexBasis[1]);

    push(CONFIG.filters[0].name, "", flexBasis[1], 1, {
        type: "select",
        chars: CONFIG.filters[0].options.map(o => o.label),
        default: CONFIG.filters[0].default,
        action: generateSelectAction(CONFIG.filters[0])
    });

    for (let i = 1; i <= 2; i++) {
        push(CONFIG.filters[i].name, "", flexBasis[2], 1, {
            type: "select",
            chars: CONFIG.filters[i].options.map(o => o.label),
            default: CONFIG.filters[i].default,
            action: generateSelectAction(CONFIG.filters[i])
        });
    }

    push(CONFIG.filters[3].name, "", flexBasis[1], 1, {
        type: "select",
        chars: CONFIG.filters[3].options.map(o => o.label),
        default: CONFIG.filters[3].default,
        action: generateSelectAction(CONFIG.filters[3])
    });

    push("🏷️ 标签分类", "", flexBasis[1]);

    CONFIG.tags.forEach(tag => {
        push(tag.name, buildUrl.call(self, tag.tag), flexBasis[4], 1, {
            action: `show('currentTag', '${tag.tag}')`
        });
    });

    push("❌ 清除标签", buildUrl.call(self, ""), flexBasis[4], 1, {
        action: "show('currentTag', '')"
    });

    result = JSON.stringify(all);
} catch (e) {
    java.longToast("发现页加载失败：" + e.message);
    result = "[]";
}

