@js:if(book.type==64||book.type==1088){
    let results = [];
    let searchTerm = "<amp-img";
    let index = 0;

    let startPos = result.indexOf('<div id="page">');
    let endPos   = result.indexOf('<div id="paginator_area">', startPos);

    while (index < result.length) {

        let imgPathIndex = result.indexOf(searchTerm, index);
        if (imgPathIndex === -1) break;

        if (
            startPos !== -1 &&
            endPos !== -1 &&
            (imgPathIndex < startPos || imgPathIndex > endPos)
        ) {
            index = imgPathIndex + searchTerm.length;
            continue;
        }

        let pathStart = imgPathIndex + searchTerm.length + 25;
        let pathEnd = result.indexOf("\"", pathStart);
        if (pathEnd === -1) break;

        let path = result.slice(pathStart, pathEnd);

        /* ===== ⭐ ：过滤非法图片页 ===== */
        if (
            !path ||
            path.indexOf("http") !== 0 ||
            (
                path.indexOf(".jpg") === -1 &&
                path.indexOf(".jpeg") === -1 &&
                path.indexOf(".png") === -1 &&
                path.indexOf(".webp") === -1
            )
        ) {
            index = pathStart + 200;
            continue;
        }
        /* ===== 结束 ===== */

        results.push(path);
        index = pathStart + 200;
    }

    result=[]
    results.map(i=>result.push("<img src=\""+i+"\">"))
    result.join("")

}else{
    let pathStart = result.indexOf("source") +12
    let path = result.slice(pathStart, result.indexOf("\"",pathStart));
    java.startBrowser(path,book.name)
    path
}

