ruleToc.chapterList:
@js:
n=result.match(/共(\d+)页/)[1];
list=[];
list.push({name:'第1页',url:baseUrl});
for(var i=2;i<=n;i++){
url1=baseUrl.replace(/.html/,'')+'_'+i+'.html';
list.push({name:'第'+i+'页',url:url1});
}list

