@js:
var result = [];
var seenTitles = new Set();
java.toast("📖动态获取中……");

// 获取首页热门搜索
var homeHtml = java.ajax("https://www.tuzac.com");
if (homeHtml) {
    result.push({
        "title": "🔥热门搜索🔥",
        "url": "",
        "style": {"layout_flexGrow":1, "layout_flexBasisPercent":1}
    });

    var doc = org.jsoup.Jsoup.parse(homeHtml);
    var hotLinks = doc.select(".hot-searches a.hot-modal");

    for (var i = 0; i < hotLinks.size(); i++) {
        var a = hotLinks.get(i);
        var title = a.text();
        // 构造分页URL：/search/{{page}}?term=xxx
        var url = a.attr("href").replace("search", "search/{{page}}"); 
        result.push({
            "title": title,
            "url": url,
            "style": {"layout_flexGrow":1, "layout_flexBasisPercent":0.25}
        });
    }
}

result.push({
    "title": "🔖标签分类🔖",
    "url": "",
    "style": {"layout_flexGrow":1, "layout_flexBasisPercent":1}
});

// 获取最大页数
var getMaxPage = function() {
    var html = java.ajax("https://www.tuzac.com/all-tags?sort=4");
    if (!html) return 1;

    var doc = org.jsoup.Jsoup.parse(html);
    var lastPage = doc.selectFirst("#pager a:contains(末页)");
    if (lastPage) {
        var href = lastPage.attr("href");
        var pageNum = href.match(/\/all-tags\/(\d+)/)?.[1] || 1;
        java.toast("📚检测到" + pageNum + "页分类");
        return parseInt(pageNum);
    }
    return 1;
};

var maxPage = getMaxPage();
var start = new Date().getTime();
while (new Date().getTime() < start + 3000);
java.toast("😘内容过多,请耐心等待😘");

// 分类抓取主循环
for (var page = 1; page <= maxPage; page++) {
    var url = page === 1 
        ? "https://www.tuzac.com/all-tags?sort=4" 
        : "https://www.tuzac.com/all-tags/" + page + "?sort=4";

    var html = java.ajax(url);
    if (!html) continue;

    var links = org.jsoup.Jsoup.parse(html).select(".teaser-thumbnail a");
    for (var i = 0; i < links.size(); i++) {
        var a = links.get(i);
        var title = a.text().trim();
        var url = a.attr("href") + "/{{page}}";
        // 分类去重
        if (!seenTitles.has(title)) {
            result.push({
                "title": title,
                "url": url,
                "style": {"layout_flexGrow":1, "layout_flexBasisPercent":0.4}
            });
            seenTitles.add(title);
        }
    }
}

JSON.stringify(result);

