var result = [];
var push = (title, url, size) => result.push({
  title: title,
  url: url,
  style: {
    layout_flexGrow: 1,
    layout_flexBasisPercent: size
  }
});
var tabList = [source.key + "/tvb/", source.key + "/tnt/"];
java.ajaxAll(tabList).forEach((response, index) => {
	let isTag = index == 0;
	push(isTag ? "分类" : "排行", null, 1);
org.jsoup.Jsoup.parse(response.body()).select('.class .container a').forEach(e => push(e.text(), String(e.attr('href')).replace(/\d+\/$/, "") + (isTag ? "{{page}}/" : "?page={{page}}"), 0.25))
});
JSON.stringify(result);

